import { useState, useEffect, useRef } from "react";

const C = {
  bg:"#080a08",bg2:"#0c100c",bg3:"#111611",bg4:"#182018",
  panel:"#0f140f",panelLight:"#152015",
  green:"#00ff6a",greenDark:"#00cc55",greenDim:"#00aa44",greenMuted:"#1a4a2a",
  border:"#1a3a1a",borderLight:"#2a5a2a",
  text:"#d0e8d0",textMuted:"#5a7a5a",
  gold:"#ffd700",goldDark:"#aa8800",
  red:"#ff3344",purple:"#aa44ff",blue:"#4488ff",cyan:"#00ddff",orange:"#ff8833",
  discord:"#5865F2",white:"#fff",
};
const F="'Rajdhani','Segoe UI',sans-serif";
const F2="'Orbitron','Rajdhani',sans-serif";

const CSS=`
@import url('https://fonts.googleapis.com/css2?family=Rajdhani:wght@400;500;600;700&family=Orbitron:wght@400;500;600;700;900&display=swap');
*{box-sizing:border-box;margin:0;padding:0}
::-webkit-scrollbar{width:5px}::-webkit-scrollbar-track{background:#0c100c}::-webkit-scrollbar-thumb{background:#1a3a1a;border-radius:3px}
@keyframes fadeIn{from{opacity:0;transform:translateY(14px)}to{opacity:1;transform:translateY(0)}}
@keyframes glow{0%,100%{filter:drop-shadow(0 0 6px rgba(0,255,106,.25))}50%{filter:drop-shadow(0 0 14px rgba(0,255,106,.5))}}
@keyframes pulse{0%,100%{box-shadow:0 0 10px rgba(0,255,106,.1)}50%{box-shadow:0 0 24px rgba(0,255,106,.3)}}
@keyframes float{0%,100%{transform:translateY(0)}50%{transform:translateY(-4px)}}
@keyframes spin{from{transform:rotate(0)}to{transform:rotate(360deg)}}
@keyframes flipIn{0%{transform:rotateY(90deg);opacity:0}100%{transform:rotateY(0);opacity:1}}
@keyframes shake{0%,100%{transform:translateX(0)}25%{transform:translateX(-4px)}75%{transform:translateX(4px)}}
@keyframes slam{0%{transform:scale(2);opacity:0}50%{transform:scale(.9)}100%{transform:scale(1);opacity:1}}
@keyframes slideR{from{opacity:0;transform:translateX(-20px)}to{opacity:1;transform:translateX(0)}}
@keyframes blink{0%,100%{opacity:.4}50%{opacity:1}}
@keyframes elimFlash{from{background:rgba(255,51,68,.15)}to{background:transparent}}
@keyframes winFlash{0%{background:rgba(0,255,106,.2)}50%{background:rgba(255,215,0,.2)}100%{background:rgba(0,255,106,.1)}}
`;

// ── ALL GAMES ──
const GAMES=[
  {id:"poker",name:"Poker Tournament",icon:"🃏",color:C.green,players:"2-64",desc:"Texas Hold'em multi-table tournament. Blind levels escalate. Last one standing wins.",tags:["Tournament","Strategy","Bluff"]},
  {id:"liars_dice",name:"Liar's Dice",icon:"🎲",color:C.orange,players:"2-8",desc:"Bluff your way to victory. Call or raise the bid — or call someone's bluff. Pirates' favorite.",tags:["Bluff","Rounds","Elimination"]},
  {id:"coinflip_br",name:"Battle Royale Flip",icon:"⚡",color:C.red,players:"4-32",desc:"Mass coinflip elimination. Each round half the players die. Last survivor takes the pot.",tags:["Fast","Luck","Elimination"]},
  {id:"blind_auction",name:"Blind Auction",icon:"🔨",color:C.purple,players:"3-16",desc:"Bid blind on mystery prizes. Highest bidder wins but pays. Psychological warfare.",tags:["Strategy","Mind Games","Economy"]},
  {id:"death_roll",name:"Death Roll",icon:"💀",color:C.red,players:"2",desc:"Take turns rolling. Number shrinks each roll. First to roll a 1 loses everything. Pure tension.",tags:["1v1","Tension","Fast"]},
  {id:"chain_duel",name:"Chain Duel",icon:"⚔️",color:C.cyan,players:"4-16",desc:"Random 1v1 bracket. Winner absorbs loser's chips. Fight your way to the championship.",tags:["Bracket","1v1","Tournament"]},
  {id:"kings_court",name:"King's Court",icon:"👑",color:C.gold,players:"3-12",desc:"The King sets challenges. Players vote to exile. Last loyal subject wins the throne.",tags:["Social","Voting","Strategy"]},
  {id:"heist",name:"The Heist",icon:"🏴‍☠️",color:"#ff4488",players:"4-8",desc:"Cooperate or betray. Split the vault — but any player can backstab for a bigger cut.",tags:["Social","Betrayal","Strategy"]},
];

const BADGE_SM="data:image/png;base64,";
const BADGE_MD="data:image/png;base64,";
const BADGE_LG="data:image/png;base64,";

function Badge({size=50}){
  const src=size<=36?BADGE_SM:size<=64?BADGE_MD:BADGE_LG;
  return(<img src={src} width={size} height={size} alt="THE69ARMY" style={{objectFit:"contain",imageRendering:"auto"}}/>);
}

function Btn({children,onClick,v="green",sz="md",disabled,style}){
  const V={green:{background:`linear-gradient(180deg,#00dd5a,#00aa44)`,borderColor:"#00ff6a",color:"#080a08"},
    dark:{background:`linear-gradient(180deg,#152015,#0f140f)`,borderColor:"#1a3a1a",color:"#00ff6a"},
    red:{background:`linear-gradient(180deg,#cc2233,#881122)`,borderColor:"#ff3344",color:"#fff"},
    discord:{background:`linear-gradient(180deg,#5865F2,#4752C4)`,borderColor:"#7289DA",color:"#fff"},
    gold:{background:`linear-gradient(180deg,#ffd700,#aa8800)`,borderColor:"#ffe033",color:"#1a1200"},
    ghost:{background:"transparent",borderColor:"#1a3a1a",color:"#5a7a5a"}};
  const S={sm:{padding:"4px 10px",fontSize:10},md:{padding:"8px 16px",fontSize:12},lg:{padding:"11px 26px",fontSize:14}};
  const vr=V[v]||V.green,si=S[sz]||S.md;
  return(<button disabled={disabled} onClick={disabled?undefined:onClick}
    onMouseEnter={e=>{if(!disabled)e.currentTarget.style.filter="brightness(1.2)";}}
    onMouseLeave={e=>{e.currentTarget.style.filter="brightness(1)";}}
    style={{fontFamily:F,fontWeight:700,cursor:disabled?"not-allowed":"pointer",border:"1.5px solid "+vr.borderColor,
      ...vr,...si,letterSpacing:1.2,textTransform:"uppercase",transition:"all .15s",opacity:disabled?.4:1,borderRadius:4,...style}}>{children}</button>);
}

function Panel({children,title,accent,style}){
  return(<div style={{background:C.panel,border:"1px solid "+C.border,borderRadius:6,
    boxShadow:"0 4px 16px rgba(0,0,0,.35)",position:"relative",overflow:"hidden",...style}}>
    {title&&<div style={{padding:"8px 14px",borderBottom:"1px solid "+C.border,fontFamily:F2,color:accent||C.green,fontSize:12,fontWeight:600,
      letterSpacing:2,textTransform:"uppercase",textShadow:"0 0 6px "+(accent||C.green)+"44",
      background:"linear-gradient(90deg,"+(accent||C.green)+"08,transparent)"}}>{title}</div>}
    {children}</div>);
}

function Inp({label,type="text",value,onChange,placeholder,style}){
  return(<div style={{marginBottom:11,...style}}>
    {label&&<label style={{display:"block",fontFamily:F,color:C.green,fontSize:10,marginBottom:3,fontWeight:600,letterSpacing:1,textTransform:"uppercase"}}>{label}</label>}
    <input type={type} value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder}
      style={{width:"100%",padding:"7px 11px",background:C.bg,border:"1px solid "+C.border,color:C.text,fontFamily:F,fontSize:13,fontWeight:500,outline:"none",borderRadius:3}}/></div>);
}

function Header({user,wallet,go}){
  return(<div style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"7px 14px",borderBottom:"1px solid "+C.border,background:C.panel}}>
    <div style={{display:"flex",alignItems:"center",gap:8,cursor:"pointer"}} onClick={()=>go("hub")}>
      <Badge size={24}/><span style={{fontFamily:F2,color:C.green,fontSize:13,fontWeight:700}}>THE69ARMY</span>
    </div>
    {user&&<div style={{display:"flex",alignItems:"center",gap:8}}>
      <div style={{fontFamily:F,fontSize:11,color:C.gold,background:C.bg,padding:"2px 8px",borderRadius:3,border:"1px solid "+C.goldDark,fontWeight:700}}>💰 {(wallet||0).toLocaleString()}</div>
      <span style={{fontFamily:F,color:C.text,fontSize:11,fontWeight:600}}>{user.username}</span>
      <Btn v="ghost" sz="sm" onClick={()=>go("landing")}>Out</Btn>
    </div>}
  </div>);
}

// ══════════════ LANDING ══════════════
